def generate_stream(self, messages: List[Dict[str, Any]], **kwargs) -> Generator[ChatMessageStreamDelta, None, None]:
        # Determine model based on message content
        last_message = messages[-1] if messages else {}
        content = last_message.get('content', '').lower()
        # Use orchestrator model for planning or final answers
        if any(keyword in content for keyword in ('plan', 'think', 'step', 'final answer', 'answer:')):
            model = self.orchestrator_model
        else:
            model = self.search_model
        try:
            # Get stream from selected model
            stream = model.generate_stream(messages, **kwargs)
            # External aggregation wrapper
            aggregated_content = ''
            token_count = 0
            for delta in stream:
                # Accumulate tokens and statistics
                if isinstance(delta, dict):
                    token = delta.get('token', '')
                else:
                    token = str(delta)
                aggregated_content += token
                token_count += 1
                # Yield ChatMessageStreamDelta with current state
                yield ChatMessageStreamDelta(
                    delta={'token': token, 'content': aggregated_content, 'token_count': token_count},
                    partial=True
                )
            # Final delta indicating completion
            yield ChatMessageStreamDelta(
                delta={'content': aggregated_content, 'token_count': token_count},
                partial=False
            )
        except Exception as e:
            # Yield error delta for upstream stability
            yield ChatMessageStreamDelta(
                delta={'error': str(e)},
                partial=False
            )

