def process_action_step(step_log: ActionStep, session_id: Optional[str] = None, skip_model_outputs: bool = False) -> Generator[DSAgentRunMessage, None, None]:
    # Header message with step title
    yield DSAgentRunMessage(
        role="assistant",
        type="header",
        content=step_log.title if hasattr(step_log, 'title') else f"Step {step_log.step_index}",
        metadata={"step_index": step_log.step_index, "session_id": session_id}
    )

    # Process thought content
    if hasattr(step_log, 'thought') and step_log.thought:
        # Preview fragment
        yield DSAgentRunMessage(
            role="assistant",
            type="thought_preview",
            content=step_log.thought[:100] + ("..." if len(step_log.thought) > 100 else ""),
            metadata={"full_thought": step_log.thought}
        )
        # Complete fragment
        yield DSAgentRunMessage(
            role="assistant",
            type="thought_complete",
            content=step_log.thought,
            metadata={}
        )

    # Process tool calls
    if hasattr(step_log, 'tool_calls') and step_log.tool_calls:
        for tool_call in step_log.tool_calls:
            # Badge message for each tool
            yield DSAgentRunMessage(
                role="assistant",
                type="tool_badge",
                content=tool_call.tool_name,
                metadata={"tool_call_id": tool_call.id, "tool_args": tool_call.arguments}
            )
            # Component message
            if tool_call.tool_name == "code_interpreter":
                yield DSAgentRunMessage(
                    role="assistant",
                    type="code_component",
                    content=tool_call.result if hasattr(tool_call, 'result') else "",
                    metadata={"language": "python", "tool_call_id": tool_call.id}
                )
            else:
                yield DSAgentRunMessage(
                    role="assistant",
                    type="chat_component",
                    content=tool_call.result if hasattr(tool_call, 'result') else "",
                    metadata={"tool_call_id": tool_call.id}
                )

    # Extract execution logs and errors
    if hasattr(step_log, 'logs') and step_log.logs:
        for log in step_log.logs:
            yield DSAgentRunMessage(
                role="assistant",
                type="terminal_log",
                content=log,
                metadata={}
            )
    if hasattr(step_log, 'error') and step_log.error:
        yield DSAgentRunMessage(
            role="assistant",
            type="error",
            content=str(step_log.error),
            metadata={"error_type": step_log.error.__class__.__name__}
        )

    # Timing information
    timing = {}
    if hasattr(step_log, 'start_time'):
        timing["start_time"] = step_log.start_time
    if hasattr(step_log, 'end_time'):
        timing["end_time"] = step_log.end_time
    if hasattr(step_log, 'duration'):
        timing["duration"] = step_log.duration
    if timing:
        yield DSAgentRunMessage(
            role="assistant",
            type="timing",
            content="",
            metadata=timing
        )

    # Footer and separator
    yield DSAgentRunMessage(
        role="assistant",
        type="footer",
        content="",
        metadata={"step_index": step_log.step_index}
    )
    yield DSAgentRunMessage(
        role="assistant",
        type="separator",
        content="",
        metadata={}
    )

